const MATRIX = {
  'SUPERVISION': {
    MINEUR:   ['10-SOP'],
    MAJEUR:   ['10-SOP', '15-SOP', '12-SOP', '11-SOP'],
    CRITIQUE: ['10-SOP', '15-SOP', '13-SOP', '11-SOP'],
  },
  'PHOTONIQUE': {
    MINEUR:   ['10-SOP', '14-SOP'],
    MAJEUR:   ['10-SOP', '14-SOP', '12-SOP', '11-SOP'],
    CRITIQUE: ['10-SOP', '14-SOP', '11-SOP', '16-SOP', '12-SOP', '17-SOP'],
  },
  'CARTE SERVICE': {
    MINEUR:   ['10-SOP', '11-SOP'],
    MAJEUR:   ['10-SOP', '11-SOP', '16-SOP'],
    CRITIQUE: ['10-SOP', '11-SOP', '16-SOP', '12-SOP'],
  },
  'CARTE MANAGEMENT': {
    MINEUR:   ['10-SOP', '15-SOP'],
    MAJEUR:   ['10-SOP', '15-SOP', '13-SOP', '16-SOP', '11-SOP'],
    CRITIQUE: ['10-SOP', '15-SOP', '13-SOP', '16-SOP', '11-SOP', '12-SOP'],
  },
  'CARTE INFRA': {
    MINEUR:   ['10-SOP', '11-SOP'],
    MAJEUR:   ['10-SOP', '11-SOP', '13-SOP', '16-SOP'],
    CRITIQUE: ['10-SOP', '11-SOP', '16-SOP', '12-SOP'],
  },
  'CHASSIS': {
    MINEUR:   ['10-SOP', '11-SOP'],
    MAJEUR:   ['10-SOP', '11-SOP', '16-SOP'],
    CRITIQUE: ['10-SOP', '14-SOP', '11-SOP', '16-SOP', '12-SOP'],
  },
  'PORT NNI': {
    MINEUR:   ['10-SOP', '14-SOP'],
    MAJEUR:   ['10-SOP', '14-SOP', '16-SOP', '11-SOP'],
    CRITIQUE: ['10-SOP', '14-SOP', '16-SOP', '11-SOP', '12-SOP'],
  },
  'PORT UNI': {
    MINEUR:   ['10-SOP', '14-SOP'],
    MAJEUR:   ['10-SOP', '14-SOP', '16-SOP'],
    CRITIQUE: ['10-SOP', '14-SOP', '16-SOP', '11-SOP'],
  },
};

const body = $input.first().json.body || $input.first().json;
const { incident_type, criticite } = body;

if (!incident_type || !criticite) {
  return [{ json: { error: 'missing incident_type or criticite', statusCode: 400 } }];
}

const sops = MATRIX[incident_type]?.[criticite] ?? ['10-SOP'];
const incident_id = 'INC-' + new Date().toISOString().replace(/[-:T.Z]/g, '').slice(0, 14);

return [{ json: { sops, sops_csv: sops.join(','), total: sops.length, incident_id } }];
